def _continuous_numpy_fallback(illuminance_lux: Float64, setpoint_lux: Float64, min_power_fraction: Float64, min_light_fraction: Float64) -> Float64:
    var fl: Float64 = (setpoint_lux - illuminance_lux) / setpoint_lux
    if setpoint_lux <= 0.0:
        return 1.0
    fl = max(0.0, min(1.0, fl))
    if fl >= 1.0:
        return 1.0
    if fl <= 0.0:
        return min_power_fraction
    var denom: Float64 = 1.0 - min_light_fraction
    if denom <= 0.0:
        return min_power_fraction
    if fl <= min_light_fraction:
        return min_power_fraction
    var fp: Float64 = (fl + (1.0 - fl) * min_power_fraction - min_light_fraction) / denom
    fp = max(min_power_fraction, min(1.0, fp))
    return fp

