def _np_ppd_from_pmv(pmv: Float64) -> Float64:
    var ppd = 100.0 - 95.0 * exp(-0.03353 * pmv * pmv * pmv * pmv - 0.2179 * pmv * pmv)
    if ppd < 5.0:
        ppd = 5.0
    if ppd > 100.0:
        ppd = 100.0
    return ppd

