def _numpy_counterflow_eff(ntu: Float64, c_ratio: Float64) -> Float64:
    var delta = abs(1.0 - c_ratio)
    if delta < 1e-06:
        return ntu / (1.0 + ntu)
    var exp_term = exp(-ntu * (1.0 - c_ratio))
    return (1.0 - exp_term) / (1.0 - c_ratio * exp_term)

def _pct(part: Int, whole: Int) -> Float64:
    if whole == 0:
        return 0.0
    return 100.0 * Float64(part) / Float64(whole)

def _smooth_ramp(value: Float64, threshold: Float64, half_width: Float64, ascending: Bool) -> Float64:
    if half_width <= 0.0:
        var v = (1.0 if value >= threshold else 0.0) if ascending else (1.0 if value <= threshold else 0.0)
        return v
    var delta = value - threshold
    if ascending:
        if delta <= -half_width:
            return 0.0
        if delta >= half_width:
            return 1.0
        return 0.5 + 0.5 * (delta / half_width)
    if delta >= half_width:
        return 0.0
    if delta <= -half_width:
        return 1.0
    return 0.5 - 0.5 * (delta / half_width)

def frame_area_m2(window_width_m: Float64, window_height_m: Float64, frame_width_m: Float64) -> Float64:
    if frame_width_m <= 0.0:
        return 0.0
    var glazed_w = window_width_m - 2.0 * frame_width_m
    var glazed_h = window_height_m - 2.0 * frame_width_m
    if glazed_w <= 0.0 or glazed_h <= 0.0:
        return max(0.0, window_width_m * window_height_m)
    return window_width_m * window_height_m - glazed_w * glazed_h

